import{_ as a,H as r,f as l,i as e}from"./chunks/framework.eFU6Tutu.js";const c=JSON.parse('{"title":"Петрушка","description":"","frontmatter":{},"headers":[],"relativePath":"plants/parsley.md","filePath":"plants/parsley.md"}'),i={name:"plants/parsley.md"};function d(n,t,o,h,s,u){return r(),l("div",null,[...t[0]||(t[0]=[e('<h1 id="петрушка" tabindex="-1">Петрушка <a class="header-anchor" href="#петрушка" aria-label="Permalink to &quot;Петрушка&quot;">​</a></h1><p>Петрушка — одна из самых популярных пряных трав, которую легко вырастить на подоконнике. Она богата витаминами, неприхотлива в уходе и даёт свежую зелень почти круглый год. Листья используют в салатах, супах, соусах и как украшение блюд.</p><h2 id="описание" tabindex="-1">Описание <a class="header-anchor" href="#описание" aria-label="Permalink to &quot;Описание&quot;">​</a></h2><p>Петрушка — двулетнее травянистое растение семейства зонтичных. В первый год формирует розетку листьев и корнеплод (у корневых сортов), на второй год цветёт и даёт семена. Листья бывают гладкими или кудрявыми, ярко-зелёного цвета. Высота куста — 20–40 см. Растение холодостойкое, но на подоконнике лучше держать его в тепле.</p><h2 id="популярные-сорта-для-дома" tabindex="-1">Популярные сорта для дома <a class="header-anchor" href="#популярные-сорта-для-дома" aria-label="Permalink to &quot;Популярные сорта для дома&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Сорт</th><th>Тип</th><th>Особенности</th></tr></thead><tbody><tr><td><strong>Обыкновенная листовая</strong></td><td>Листовая</td><td>Классический вкус и аромат, быстро растёт</td></tr><tr><td><strong>Кудрявая</strong></td><td>Листовая</td><td>Декоративные волнистые листья, дольше хранится</td></tr><tr><td><strong>Богатырь</strong></td><td>Листовая</td><td>Крупные листья, высокая урожайность</td></tr><tr><td><strong>Астра</strong></td><td>Листовая</td><td>Раннеспелая, густая розетка, компактная</td></tr><tr><td><strong>Урожайная</strong></td><td>Корневая</td><td>Образует корнеплод, зелень тоже можно срезать</td></tr><tr><td><strong>Бисер</strong></td><td>Листовая</td><td>Раннеспелый сорт для подоконника</td></tr></tbody></table><h2 id="уход" tabindex="-1">Уход <a class="header-anchor" href="#уход" aria-label="Permalink to &quot;Уход&quot;">​</a></h2><p>Подробнее об уходе за петрушкой и другой зеленью читайте в <a href="/care/greens/#петрушка">гайде по уходу за зеленью</a>.</p><h2 id="как-использовать-в-еде" tabindex="-1">Как использовать в еде <a class="header-anchor" href="#как-использовать-в-еде" aria-label="Permalink to &quot;Как использовать в еде&quot;">​</a></h2><ul><li>Свежие салаты (петрушка + огурцы + помидоры)</li><li>Посыпка для супов и бульонов</li><li>Зелёный смузи</li><li>Соусы (чесночная заправка)</li><li>Украшение горячих блюд</li><li>Заморозка на зиму</li></ul><h2 id="полезные-своиства" tabindex="-1">Полезные свойства <a class="header-anchor" href="#полезные-своиства" aria-label="Permalink to &quot;Полезные свойства&quot;">​</a></h2><ul><li>Богата витаминами С, А, К, группы В</li><li>Содержит железо, калий и фолиевую кислоту</li><li>Укрепляет иммунитет</li><li>Улучшает пищеварение</li><li>Освежает дыхание</li><li>Обладает мочегонным действием</li></ul><h2 id="источники-информации" tabindex="-1">Источники информации <a class="header-anchor" href="#источники-информации" aria-label="Permalink to &quot;Источники информации&quot;">​</a></h2><ul><li><a href="https://azbyka.ru/garden/kak-vyrastit-petrushku-na-podokonnike-i-na-balkone/" target="_blank" rel="noreferrer">Азбука садовода — Петрушка на подоконнике</a></li><li><a href="https://pogoda.mail.ru/news/61955466/" target="_blank" rel="noreferrer">Погода Mail — Как вырастить петрушку</a></li><li><a href="https://ru.ruwiki.ru/wiki/%D0%9F%D0%B5%D1%82%D1%80%D1%83%D1%88%D0%BA%D0%B0" target="_blank" rel="noreferrer">РуВики — Петрушка</a></li></ul><h2 id="похожие-растения" tabindex="-1">Похожие растения <a class="header-anchor" href="#похожие-растения" aria-label="Permalink to &quot;Похожие растения&quot;">​</a></h2><ul><li><a href="/plants/dill.html">Укроп</a></li><li><a href="/plants/salad.html">Салаты</a></li><li><a href="/plants/chives.html">Лук (зелёный)</a></li><li><a href="/plants/basil.html">Базилик</a></li></ul>',16)])])}const f=a(i,[["render",d]]);export{c as __pageData,f as default};
